#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#define MAX_NODES 10000

// Structure to represent a graph
typedef struct {
    int numNodes;
    int** adjLists;
} Graph;

// Function to create a graph
Graph* createGraph(int numNodes) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numNodes = numNodes;
    graph->adjLists = (int**) malloc(numNodes * sizeof(int*));
    for (int i = 0; i < numNodes; i++) {
        graph->adjLists[i] = NULL;
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    int* newList = (int*) malloc(2 * sizeof(int));
    newList[0] = dest;
    newList[1] = -1; // sentinel value to mark end of list
    if (graph->adjLists[src] == NULL) {
        graph->adjLists[src] = newList;
    } else {
        int* current = graph->adjLists[src];
        while (current[1] != -1) {
            current += 2;
        }
        current[1] = dest;
    }
}

// Function to find safe nodes in the graph
void findSafeNodes(Graph* graph) {
    bool* safe = (bool*) malloc(graph->numNodes * sizeof(bool));
    for (int i = 0; i < graph->numNodes; i++) {
        safe[i] = false;
    }
    // Mark terminal nodes as safe
    for (int i = 0; i < graph->numNodes; i++) {
        if (graph->adjLists[i] == NULL) {
            safe[i] = true;
        }
    }
    // Perform BFS traversal from each terminal node
    for (int i = 0; i < graph->numNodes; i++) {
        if (safe[i]) {
            int* queue = (int*) malloc(graph->numNodes * sizeof(int));
            int front = 0, rear = 0;
            queue[rear++] = i;
            while (front < rear) {
                int node = queue[front++];
                int* adjList = graph->adjLists[node];
                while (adjList != NULL && adjList[0] != -1) {
                    int neighbor = adjList[0];
                    if (!safe[neighbor]) {
                        safe[neighbor] = true;
                        queue[rear++] = neighbor;
                    }
                    adjList += 2;
                }
            }
            free(queue);
        }
    }
    // Print safe nodes
    for (int i = 0; i < graph->numNodes; i++) {
        if (safe[i]) {
            printf("%d ", i);
        }
    }
    printf("\n");
    free(safe);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        Graph* graph = createGraph(n);
        for (int i = 0; i < n; i++) {
            int numEdges;
            scanf("%d", &numEdges);
            for (int j = 0; j < numEdges; j++) {
                int dest;
                scanf("%d", &dest);
                addEdge(graph, i, dest);
            }
        }
        findSafeNodes(graph);
        // Free graph memory
        for (int i = 0; i < n; i++) {
            free(graph->adjLists[i]);
        }
        free(graph->adjLists);
        free(graph);
    }
    return 0;
}

