#include <queue>
using namespace std;

// Structure to represent a graph
struct Graph {
    int numNodes;
    vector<vector<int>> adjLists;
};

// Function to create a graph
Graph createGraph(int numNodes) {
    Graph graph;
    graph.numNodes = numNodes;
    graph.adjLists.resize(numNodes);
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph& graph, int src, int dest) {
    graph.adjLists[src].push_back(dest);
}

// Function to find safe nodes in the graph
void findSafeNodes(Graph& graph) {
    vector<bool> safe(graph.numNodes, false);
    // Mark terminal nodes as safe
    for (int i = 0; i < graph.numNodes; i++) {
        if (graph.adjLists[i].empty()) {
            safe[i] = true;
        }
    }
    // Perform BFS traversal from each terminal node
    for (int i = 0; i < graph.numNodes; i++) {
        if (safe[i]) {
            queue<int> q;
            q.push(i);
            while (!q.empty()) {
                int node = q.front();
                q.pop();
                for (int neighbor : graph.adjLists[node]) {
                    if (!safe[neighbor]) {
                        safe[neighbor] = true;
                        q.push(neighbor);
                    }
                }
            }
        }
    }
    // Print safe nodes
    for (int i = 0; i < graph.numNodes; i++) {
        if (safe[i]) {
            cout << i << " ";
        }
    }
    cout << endl;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int n;
