import java.util.Scanner;
import java.util.Queue;
import java.util.LinkedList;
public class Main {
    // Structure to represent a graph
    static class Graph {
        int numNodes;
        int[][] adjLists;
        Graph(int numNodes) {
            this.numNodes = numNodes;
            adjLists = new int[numNodes][];
        }
    }

    // Function to create a graph
    static Graph createGraph(int numNodes) {
        return new Graph(numNodes);
    }

    // Function to add an edge to the graph
    static void addEdge(Graph graph, int src, int dest) {
        int[] newList = new int[1];
        newList[0] = dest;
        if (graph.adjLists[src] == null) {
            graph.adjLists[src] = newList;
        } else {
            int[] current = graph.adjLists[src];
            int[] newList2 = new int[current.length + 1];
            System.arraycopy(current, 0, newList2, 0, current.length);
            newList2[current.length] = dest;
            graph.adjLists[src] = newList2;
        }
    }

    // Function to find safe nodes in the graph
    static void findSafeNodes(Graph graph) {
        boolean[] safe = new boolean[graph.numNodes];
        // Mark terminal nodes as safe
        for (int i = 0; i < graph.numNodes; i++) {
            if (graph.adjLists[i] == null) {
                safe[i] = true;
            }
        }
        // Perform BFS traversal from each terminal node
        for (int i = 0; i < graph.numNodes; i++) {
            if (safe[i]) {
                Queue<Integer> q = new LinkedList<>();
                q.add(i);
                while (!q.isEmpty()) {
                    int node = q.poll();
                    if (graph.adjLists[node] != null) {
                        for (int neighbor : graph.adjLists[node]) {
                            if (!safe[neighbor]) {
                                safe[neighbor] = true;
                                q.add(neighbor);
                            }
                        }
                    }
                }
            }
        }
        // Print safe nodes
        for (int i = 0; i < graph.numNodes; i++) {
            if (safe[i]) {
                System.out.print(i + " ");
            }
        }
        System.out.println();
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            Graph graph = createGraph(n);
            for (int i = 0; i < n; i++) {
                int numEdges = sc.nextInt();
                for (int j = 0; j < numEdges; j++) {
                    int dest = sc.nextInt();
                    addEdge(graph, i, dest);
                }
            }
            findSafeNodes(graph);
        }
    }
}

