function addEdge(graph, src, dest) {
    graph.adjLists[src].push(dest);
}

// Function to find safe nodes in the graph
function findSafeNodes(graph) {
    const safe = Array(graph.numNodes).fill(false);
    // Mark terminal nodes as safe
    for (let i = 0; i < graph.numNodes; i++) {
        if (graph.adjLists[i].length === 0) {
            safe[i] = true;
        }
    }
    // Perform BFS traversal from each terminal node
    for (let i = 0; i < graph.numNodes; i++) {
        if (safe[i]) {
            const q = [i];
            while (q.length > 0) {
                const node = q.shift();
                for (const neighbor of graph.adjLists[node]) {
                    if (!safe[neighbor]) {
                        safe[neighbor] = true;
                        q.push(neighbor);
                    }
                }
            }
        }
    }
    // Print safe nodes
    for (let i = 0; i < graph.numNodes; i++) {
        if (safe[i]) {
            process.stdout.write(`${i} `);
        }
    }
    process.stdout.write('\n');
}

